import { get, post } from "../utils/request";

// Login: Sửa lại để gửi username và password trong body thay vì query parameters
export const login = async (username, password) => {
  const payload = {
    username,
    password,
  };
  const result = await post("api/auth/login", payload); // Gửi payload trong body
  return result;
};

// Register: Không cần sửa vì đã đúng cách
export const register = async (options) => {
  const result = await post("api/auth/register", options);
  return result;
};
